import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Divider,
  Box,
  MotionKeyframes,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string; // Default to 'C'
  /** 5-day forecast array */
  forecast: Array<{
    day?: string;
    icon?: string;
    high?: number;
    low?: number;
  }>;
}

/**
 * WeatherCard Component
 * Provides a visually rich, responsive display for current weather and forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  const displayUnit = `°${unit}`;

  return (
    <section
      style={{
        maxWidth: '400px',
        width: '100%',
        margin: '0 auto',
      }}
    >
      <MotionKeyframes />
      <Card
        shadow="md"
        radius="xl"
        padding={24}
        border={true}
        style={{
          backgroundColor: 'var(--ggui-color-surface)',
          animation: 'ggui-slideInUp 300ms ease-out both',
        }}
      >
        <Stack direction="vertical" gap={20}>
          {/* Header Section */}
          <Stack direction="horizontal" justify="between" align="start">
            <Stack direction="vertical" gap={2}>
              <Heading level={2} color="var(--ggui-color-onSurface)">
                {city}
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {new Date().toLocaleDateString(undefined, {
                  weekday: 'long',
                  month: 'short',
                  day: 'numeric',
                })}
              </Text>
            </Stack>
            <Box
              paddingX={12}
              paddingY={4}
              background="var(--ggui-color-primary-50)"
              borderRadius="var(--ggui-shape-radius-full)"
            >
              <Text variant="label" color="var(--ggui-color-primary-700)">
                {condition}
              </Text>
            </Box>
          </Stack>

          {/* Main Hero Section */}
          <Stack direction="horizontal" justify="center" align="center" gap={24}>
            <Stack direction="horizontal" align="start" gap={2}>
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-primary-600)"
                style={{ lineHeight: 1 }}
              >
                {temperature}
              </Text>
              <Text
                size="xl"
                weight="semibold"
                color="var(--ggui-color-primary-600)"
                style={{ marginTop: 'var(--ggui-spacing-1)' }}
              >
                {displayUnit}
              </Text>
            </Stack>
          </Stack>

          {/* Stats Section */}
          <Stack direction="horizontal" justify="around" gap={16}>
            <Box
              style={{ flex: 1 }}
              padding={12}
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Stack align="center" gap={4}>
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant)"
                >
                  Humidity
                </Text>
                <Text weight="bold" color="var(--ggui-color-onSurface)">
                  {humidity}%
                </Text>
              </Stack>
            </Box>
            <Box
              style={{ flex: 1 }}
              padding={12}
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Stack align="center" gap={4}>
                <Stack direction="horizontal" align="center" gap={4}>
                  <Icon
                    name="menu"
                    size={14}
                    color="var(--ggui-color-onSurfaceVariant)"
                  />
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    Wind
                  </Text>
                </Stack>
                <Text weight="bold" color="var(--ggui-color-onSurface)">
                  {windSpeed} km/h
                </Text>
              </Stack>
            </Box>
          </Stack>

          <Divider orientation="horizontal" margin={16} color="var(--ggui-color-outlineVariant)" />

          {/* Forecast Section */}
          <Stack
            direction="horizontal"
            justify="between"
            gap={8}
            style={{ overflowX: 'auto' }}
          >
            {forecast.map((f, i) => (
              <Stack
                key={i}
                align="center"
                gap={4}
                style={{ flex: 1, minWidth: '60px' }}
              >
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  {f.day}
                </Text>
                <Text size="lg">
                  {f.icon}
                </Text>
                <Stack direction="horizontal" align="center" gap={4}>
                  <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)">
                    {f.high}°
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {f.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </section>
  );
}
